# DK VNT.  Varde - Nørre Nebel – Tarm
#
let vt = path("d3.dk.vnt");

with detail = 3,
     railway = :first :pax
{
    # point.dk.Varde  dk.LES

    with link = "point.dk.Arnbjerg", railway = :station {
        track(vt[:arn - 0.5sw, :arn + 0.5sw] << 1ms << 1mt);
        marker(:left :de.hp :removed,
            vt[:arn] << 1ms << 1.5mt, vt[:arn] << 1ms << 0.5mt
        );
    }

    with link = "line.dk.VNT" {
        track(:ror,
                vt[:arn + 0.49sw, :var.yn - 1mt] << 1ms << 1mt
            ..  vt[:fri - 0.5sw, :fri - 0.49sw]
        );
    }

    with link = "point.dk.Frisvadvej", railway = :station {
        track(vt[:fri - 0.5sw, :fri + 0.5sw]);
        marker(:left :de.hp, vt[:fri] << 0.5mt);
        slabel(:left, vt[:fri] >> 0.5mt + (1dt, -1.5dt),
            vbox(:right:base, "Frisvad- ", "vej")
        );
    }

    with link = "line.dk.VNT" {
        track(vt[:fri + 0.49sw, :vav - 0.49sw]);
    }

    with link = "point.dk.Varde-Vest", railway = :station {
